import * as React from "react"
import * as styles from "../styles/ProductCard.module.css"
import hoaImage from "../images/HOA.png"

export const ProductCard = ({ title, price, description }) => (
  <div className={styles.card}>
    <img src={hoaImage} alt="product" width={200} style={{ display: "block" }} />
    <h3>{title}</h3>
    <p>{description}</p>
    <div className={styles.price}>{price}</div>
  </div>
)